328	
329	        for m in matches {
330	            let m = match m {
331	                Ok(m) => m,
332	                Err(_) => continue,
333	            };
334	
335	            let mut import_path = String::new();
336	            let mut alias = None;
337	            let mut import_line: u64 = 0;
338	
339	            for capture in m.captures {
340	                let node = capture.node;
341	                let capture_name = query.capture_names()[capture.index as usize];
342	
343	                match capture_name {
344	                    "import.path" => {
345	                        import_path = self.node_text(node, source).to_string();
346	                    }
347	                    "import.name" => {
348	                        alias = Some(self.node_text(node, source).to_string());
349	                    }
350	                    "import" | "import.extern" => {
351	                        import_line = node.start_position().row as u64 + 1;
352	                    }
353	                    _ => {}
354	                }
355	            }
356	
357	            if !import_path.is_empty() {
358	                results.push(Import {
359	                    file_path: file_path_str.clone(),
360	                    import_path,
361	                    alias,
362	                    line: import_line,
363	                    resolution: ImportResolution::Unresolved,
364	                });
365	            }
366	        }
367	
368	        results
369	    }
370	
371	    fn infer_package(&self, file_path: &Path, _source: &str) -> Option<String> {
372	        // Rust 项目：从 Cargo.toml 所在目录名推断 crate 名
373	        // 此处简化，使用文件路径的根级目录名
374	        let components: Vec<_> = file_path.components().collect();
375	        for component in components.iter().rev() {
376	            if let std::path::Component::Normal(name) = component {
377	                if name == "src" {
378	                    continue;
379	                }
380	                return name.to_str().map(|s| s.to_string());
381	            }
382	        }
383	        None
384	    }
385	}
