//! Rust 语言解析器
//!
//! 使用 tree-sitter-rust grammar 解析 .rs 文件，
//! 提取函数、结构体、trait、枚举、方法等符号定义，
//! 以及函数调用和 use 导入语句。

use std::path::Path;
use std::sync::Mutex;

use codeconnect_core::error::CodeConnectError;
use codeconnect_core::symbol_id::StableSymbolId;
use codeconnect_core::types::{
    CallSite, CallType, Import, ImportResolution, SourceLocation, Symbol, SymbolKind,
};
use tree_sitter::{Parser, Query, QueryCursor, Tree};

use crate::query_loader::load_rust_queries;
use crate::trait::LanguageParser;

/// Rust 语言解析器
pub struct RustParser {
    /// tree-sitter 解析器实例（Mutex 因为 Parser 不是 Sync）
    parser: Mutex<Parser>,
}

impl RustParser {
    /// 创建新的 Rust 解析器
    pub fn new() -> Self {
        let mut parser = Parser::new();
        parser
            .set_language(&tree_sitter_rust::LANGUAGE.into())
            .expect("加载 Rust tree-sitter grammar 失败");
        Self {
            parser: Mutex::new(parser),
        }
    }

    /// 将 tree-sitter 节点转为源码位置
    fn node_to_location(&self, source: &str, node: tree_sitter::Node) -> SourceLocation {
        let start = node.start_position();
        let end = node.end_position();
        SourceLocation {
            file_path: String::new(),
            line: start.row as u64 + 1,
            column: start.column as u64 + 1,
            end_line: end.row as u64 + 1,
            end_column: end.column as u64 + 1,
        }
    }

    /// 获取节点的源码文本
    fn node_text<'a>(&self, node: tree_sitter::Node, source: &'a str) -> &'a str {
        node.utf8_text(source.as_bytes()).unwrap_or("")
    }
}

impl Default for RustParser {
    fn default() -> Self {
        Self::new()
    }
}

impl LanguageParser for RustParser {
    fn language(&self) -> &'static str {
        "rust"
    }

    fn file_extensions(&self) -> &[&str] {
        &["rs"]
    }

    fn parse(&self, source: &str) -> Result<Tree, CodeConnectError> {
        let mut parser = self
            .parser
            .lock()
            .map_err(|e| CodeConnectError::Parse {
                file: Path::new("").to_path_buf(),
                message: format!("获取解析器锁失败: {}", e),
            })?;
        parser
            .parse(source, None)
            .ok_or_else(|| CodeConnectError::Parse {
                file: Path::new("").to_path_buf(),
                message: "Rust 源码解析失败，可能包含语法错误".to_string(),
            })
    }

    fn extract_symbols(
        &self,
        tree: &Tree,
        source: &str,
        file_path: &Path,
    ) -> Vec<Symbol> {
        let queries = load_rust_queries();
        let file_path_str = file_path.to_string_lossy().to_string();
        let mut results = Vec::new();

        let query = match Query::new(&tree_sitter_rust::LANGUAGE.into(), &queries.symbols) {
            Ok(q) => q,
            Err(_) => return results,
        };

        let mut cursor = QueryCursor::new();
        let matches = cursor.matches(&query, tree.root_node(), source.as_bytes());

        for m in matches {
            let m = match m {
                Ok(m) => m,
                Err(_) => continue,
            };

            let mut name = String::new();
            let mut parent = String::new();
            let mut kind = SymbolKind::Unknown("unknown".to_string());
            let mut location = SourceLocation {
                file_path: file_path_str.clone(),
                line: 0,
                column: 0,
                end_line: 0,
                end_column: 0,
            };

            for capture in m.captures {
                let node = capture.node;
                let capture_name = query.capture_names()[capture.index as usize];

                match capture_name {
                    "symbol.name" => {
                        name = self.node_text(node, source).to_string();
                    }
                    "symbol.function" => {
                        kind = SymbolKind::Function;
                        location = self.node_to_location(source, node);
                    }
                    "symbol.method" => {
                        kind = SymbolKind::Method;
                        location = self.node_to_location(source, node);
                    }
                    "symbol.struct" => {
                        kind = SymbolKind::Struct;
                        location = self.node_to_location(source, node);
                    }
                    "symbol.trait" => {
                        kind = SymbolKind::Trait;
                        location = self.node_to_location(source, node);
                    }
                    "symbol.enum" => {
                        kind = SymbolKind::Enum;
                        location = self.node_to_location(source, node);
                    }
                    "symbol.type_alias" => {
                        kind = SymbolKind::TypeAlias;
                        location = self.node_to_location(source, node);
                    }
                    "symbol.macro" => {
                        kind = SymbolKind::Macro;
                        location = self.node_to_location(source, node);
                    }
                    "symbol.module" => {
                        kind = SymbolKind::Module;
                        location = self.node_to_location(source, node);
                    }
                    "symbol.variable" => {
                        kind = SymbolKind::Variable;
                        location = self.node_to_location(source, node);
                    }
                    "symbol.field" => {
                        kind = SymbolKind::Field;
                        location = self.node_to_location(source, node);
                    }
                    "symbol.parent" => {
                        parent = self.node_text(node, source).to_string();
                    }
                    _ => {}
                }
            }

            if name.is_empty() {
                continue;
            }

            let kind_str = match &kind {
                SymbolKind::Function => "function",
                SymbolKind::Method => "method",
                SymbolKind::Struct => "struct",
                SymbolKind::Trait => "trait",
                SymbolKind::Enum => "enum",
                SymbolKind::TypeAlias => "type_alias",
                SymbolKind::Macro => "macro",
                SymbolKind::Module => "module",
                SymbolKind::Variable => "variable",
                SymbolKind::Field => "field",
                _ => "unknown",
            };

            let id = StableSymbolId::new("rust", &file_path_str, kind_str, &name);

            // Rust 顶层符号默认是私有的（没有 pub 修饰符时）
            let is_exported = name.chars().next().map_or(false, |c| c.is_uppercase())
                || matches!(
                    kind,
                    SymbolKind::Function
                        | SymbolKind::Struct
                        | SymbolKind::Trait
                        | SymbolKind::Enum
                );

            let parent_id = if parent.is_empty() {
                None
            } else {
                Some(
                    StableSymbolId::new("rust", &file_path_str, "struct", &parent)
                        .to_string(),
                )
            };

            let modifiers = if is_exported {
                vec!["pub".to_string()]
            } else {
                vec!["private".to_string()]
            };

            results.push(Symbol {
                id: id.to_string(),
                name,
                kind,
                location,
                signature: None,
                doc_comment: None,
                parent_id,
                modifiers,
                is_exported,
                complexity: None,
            });
        }

        results
    }

    fn extract_calls(
        &self,
        tree: &Tree,
        source: &str,
        file_path: &Path,
    ) -> Vec<CallSite> {
        let queries = load_rust_queries();
        let file_path_str = file_path.to_string_lossy().to_string();
        let mut results = Vec::new();

        let query = match Query::new(&tree_sitter_rust::LANGUAGE.into(), &queries.calls) {
            Ok(q) => q,
            Err(_) => return results,
        };

        let mut cursor = QueryCursor::new();
        let matches = cursor.matches(&query, tree.root_node(), source.as_bytes());

        for m in matches {
            let m = match m {
                Ok(m) => m,
                Err(_) => continue,
            };

            let mut callee_name = String::new();
            let mut call_type = CallType::Direct;
            let mut location = SourceLocation {
                file_path: file_path_str.clone(),
                line: 0,
                column: 0,
                end_line: 0,
                end_column: 0,
            };

            for capture in m.captures {
                let node = capture.node;
                let capture_name = query.capture_names()[capture.index as usize];

                match capture_name {
                    "call.name" => {
                        callee_name = self.node_text(node, source).to_string();
                    }
                    "call" => {
                        location = self.node_to_location(source, node);
                    }
                    "call.method" => {
                        call_type = CallType::Virtual;
                        location = self.node_to_location(source, node);
                    }
                    "call.macro" => {
                        call_type = CallType::MacroExpansion;
                        location = self.node_to_location(source, node);
                    }
                    _ => {}
                }
            }

            if !callee_name.is_empty() && location.line > 0 {
                results.push(CallSite {
                    caller_id: String::new(),
                    callee_name,
                    location,
                    call_type,
                    confidence: 0.9,
                });
            }
        }

        results
    }

    fn extract_imports(
        &self,
        tree: &Tree,
        source: &str,
        file_path: &Path,
    ) -> Vec<Import> {
        let queries = load_rust_queries();
        let file_path_str = file_path.to_string_lossy().to_string();
        let mut results = Vec::new();

        let query = match Query::new(&tree_sitter_rust::LANGUAGE.into(), &queries.imports) {
            Ok(q) => q,
            Err(_) => return results,
        };

        let mut cursor = QueryCursor::new();
        let matches = cursor.matches(&query, tree.root_node(), source.as_bytes());

        for m in matches {
            let m = match m {
                Ok(m) => m,
                Err(_) => continue,
            };

            let mut import_path = String::new();
            let mut alias = None;
            let mut import_line: u64 = 0;

            for capture in m.captures {
                let node = capture.node;
                let capture_name = query.capture_names()[capture.index as usize];

                match capture_name {
                    "import.path" => {
                        import_path = self.node_text(node, source).to_string();
                    }
                    "import.name" => {
                        alias = Some(self.node_text(node, source).to_string());
                    }
                    "import" | "import.extern" => {
                        import_line = node.start_position().row as u64 + 1;
                    }
                    _ => {}
                }
            }

            if !import_path.is_empty() {
                results.push(Import {
                    file_path: file_path_str.clone(),
                    import_path,
                    alias,
                    line: import_line,
                    resolution: ImportResolution::Unresolved,
                });
            }
        }

        results
    }

    fn infer_package(&self, file_path: &Path, _source: &str) -> Option<String> {
        // Rust 项目：从 Cargo.toml 所在目录名推断 crate 名
        // 此处简化，使用文件路径的根级目录名
        let components: Vec<_> = file_path.components().collect();
        for component in components.iter().rev() {
            if let std::path::Component::Normal(name) = component {
                if name == "src" {
                    continue;
                }
                return name.to_str().map(|s| s.to_string());
            }
        }
        None
    }
}

//! 导入解析器
//!
//! 将调用点的被调用者名称解析为稳定的符号 ID。
//! 每种语言实现自己的导入解析策略：
//！ - Rust: use 语句 → mod 树 → Cargo.toml 依赖
//! - TypeScript: import/require → tsconfig paths → package.json
//! - Java: import → classpath → Maven/Gradle source roots
//!
//! 初期实现：返回同文件内符号的简单匹配，后续扩展跨文件解析。

use std::collections::HashMap;
use std::path::{Path, PathBuf};

use codeconnect_core::error::CodeConnectError;

/// 解析结果
#[derive(Debug, Clone)]
pub struct ResolutionResult {
    /// 候选目标符号 ID 列表
    pub candidates: Vec<CandidateTarget>,
    /// 解析策略描述
    pub strategy: String,
}

/// 候选目标
#[derive(Debug, Clone)]
pub struct CandidateTarget {
    /// 目标符号的稳定 ID
    pub symbol_id: String,
    /// 置信度 0.0-1.0
    pub confidence: f64,
    /// 解析路径描述（如 "import:std::io::Read → 同 crate 解析"）
    pub resolution_path: String,
}

/// 导入解析器 trait
///
/// 每种语言的解析器实现此 trait，提供跨文件调用目标解析能力。
pub trait ImportResolver: Send + Sync {
    /// 返回此解析器支持的语言名
    fn language(&self) -> &'static str;

    /// 解析调用目标
    ///
    /// * `callee_name` - 被调用者名称（简单名或部分限定名）
    /// * `caller_file` - 调用者文件路径
    /// * `imports` - 调用者文件内所有导入的映射（导入路径 → 已解析符号列表）
    fn resolve(
        &self,
        callee_name: &str,
        caller_file: &Path,
        imports: &HashMap<String, Vec<String>>,
    ) -> Result<ResolutionResult, CodeConnectError>;

    /// 尝试定位外部模块的文件路径
    ///
    /// 返回 `None` 表示无法解析（如系统库/std 库或第三方包）。
    fn locate_module(&self, module_path: &str, from_file: &Path) -> Option<PathBuf>;
}

/// Rust 导入解析器
///
/// 解析策略：
/// 1. 同文件内查找（当前模块内的符号）
/// 2. 同 crate 内查找（通过 mod 树遍历）
/// 3. use 导入的符号（来自 imports 参数）
/// 4. 外部 crate 依赖（标记为 external，不深入索引）
pub struct RustImportResolver;

impl ImportResolver for RustImportResolver {
    fn language(&self) -> &'static str {
        "rust"
    }

    fn resolve(
        &self,
        _callee_name: &str,
        _caller_file: &Path,
        _imports: &HashMap<String, Vec<String>>,
    ) -> Result<ResolutionResult, CodeConnectError> {
        // TODO: 实现完整的 Rust 调用目标解析
        Ok(ResolutionResult {
            candidates: vec![],
            strategy: "rust_stub".to_string(),
        })
    }

    fn locate_module(&self, _module_path: &str, _from_file: &Path) -> Option<PathBuf> {
        // TODO: 实现模块文件定位逻辑
        None
    }
}

