1	//! Rust 语言解析器
2	//!
3	//! 使用 tree-sitter-rust grammar 解析 .rs 文件，
4	//! 提取函数、结构体、trait、枚举、方法等符号定义，
5	//! 以及函数调用和 use 导入语句。
6	
7	use std::path::Path;
8	use std::sync::Mutex;
9	
10	use codeconnect_core::error::CodeConnectError;
11	use codeconnect_core::symbol_id::StableSymbolId;
12	use codeconnect_core::types::{
13	    CallSite, CallType, Import, ImportResolution, SourceLocation, Symbol, SymbolKind,
14	};
15	use tree_sitter::{Parser, Query, QueryCursor, Tree};
16	
17	use crate::query_loader::load_rust_queries;
18	use crate::r#trait::LanguageParser;
19	
20	/// Rust 语言解析器
21	///
22	/// 包装了 tree-sitter-rust grammar 和一个 `Mutex<Parser>`，
23	/// 确保并发调用时的线程安全。
24	pub struct RustParser {
25	    /// tree-sitter 解析器实例（Mutex 因为 Parser 不是 Sync）
26	    parser: Mutex<Parser>,
27	}
28	
29	impl RustParser {
30	    /// 创建新的 Rust 解析器
31	    pub fn new() -> Self {
32	        let mut parser = Parser::new();
33	        // tree-sitter 0.24: language() 函数返回 Language 引用
34	        parser
35	            .set_language(&tree_sitter_rust::language())
36	            .expect("加载 Rust tree-sitter grammar 失败");
37	        Self {
38	            parser: Mutex::new(parser),
39	        }
40	    }
41	
42	    /// 将 tree-sitter 节点转为源码位置（0-based → 1-based）
43	    fn node_to_location(&self, node: tree_sitter::Node) -> SourceLocation {
44	        let start = node.start_position();
45	        let end = node.end_position();
46	        SourceLocation {
47	            file_path: String::new(), // 由外部调用者填充
48	            line: start.row as u64 + 1,
49	            column: start.column as u64 + 1,
50	            end_line: end.row as u64 + 1,
51	            end_column: end.column as u64 + 1,
52	        }
53	    }
54	
55	    /// 获取节点的源码文本（UTF-8 安全）
56	    fn node_text<'a>(&self, node: tree_sitter::Node, source: &'a str) -> &'a str {
57	        node.utf8_text(source.as_bytes()).unwrap_or("")
58	    }
59	}
60	
61	impl Default for RustParser {
62	    fn default() -> Self {
63	        Self::new()
64	    }
65	}
66	
67	impl LanguageParser for RustParser {
68	    fn language(&self) -> &'static str {
69	        "rust"
70	    }
71	
72	    fn file_extensions(&self) -> &[&str] {
73	        &["rs"]
74	    }
75	
76	    fn parse(&self, source: &str) -> Result<Tree, CodeConnectError> {
77	        let mut parser = self.parser.lock().map_err(|e| CodeConnectError::Parse {
78	            file: Path::new("").to_path_buf(),
79	            message: format!("获取解析器锁失败: {}", e),
80	        })?;
81	        parser
82	            .parse(source, None)
83	            .ok_or_else(|| CodeConnectError::Parse {
84	                file: Path::new("").to_path_buf(),
85	                message: "Rust 源码解析失败，可能包含语法错误".to_string(),
86	            })
87	    }
88	
89	    fn extract_symbols(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<Symbol> {
90	        let queries = load_rust_queries();
91	        let file_path_str = file_path.to_string_lossy().to_string();
92	        let mut results = Vec::new();
93	
94	        let query = match Query::new(&tree_sitter_rust::language(), &queries.symbols) {
95	            Ok(q) => q,
96	            Err(_) => return results,
97	        };
98	
99	        let mut cursor = QueryCursor::new();
100	        // tree-sitter 0.24: matches() 返回 StreamingIterator，不是标准 Iterator
101	        // 使用 StreamingIterator::next(&mut self) 遍历
102	        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
103	
104	        while let Some(m) = matches.next() {
105	            let mut name = String::new();
106	            let mut parent = String::new();
107	            let mut kind = SymbolKind::Unknown("unknown".to_string());
108	            let mut location = SourceLocation {
109	                file_path: file_path_str.clone(),
110	                line: 0,
111	                column: 0,
112	                end_line: 0,
113	                end_column: 0,
114	            };
115	
116	            for capture in m.captures {
117	                let node = capture.node;
118	                let capture_name = query.capture_names()[capture.index as usize];
119	
120	                match capture_name {
121	                    "symbol.name" => {
122	                        name = self.node_text(node, source).to_string();
123	                    }
124	                    "symbol.function" => {
125	                        kind = SymbolKind::Function;
126	                        location = self.node_to_location(node);
127	                    }
128	                    "symbol.method" => {
129	                        kind = SymbolKind::Method;
130	                        location = self.node_to_location(node);
131	                    }
132	                    "symbol.struct" => {
133	                        kind = SymbolKind::Struct;
134	                        location = self.node_to_location(node);
135	                    }
136	                    "symbol.trait" => {
137	                        kind = SymbolKind::Trait;
138	                        location = self.node_to_location(node);
139	                    }
140	                    "symbol.enum" => {
141	                        kind = SymbolKind::Enum;
142	                        location = self.node_to_location(node);
143	                    }
144	                    "symbol.type_alias" => {
145	                        kind = SymbolKind::TypeAlias;
146	                        location = self.node_to_location(node);
147	                    }
148	                    "symbol.macro" => {
149	                        kind = SymbolKind::Macro;
150	                        location = self.node_to_location(node);
151	                    }
152	                    "symbol.module" => {
153	                        kind = SymbolKind::Module;
154	                        location = self.node_to_location(node);
155	                    }
156	                    "symbol.variable" => {
157	                        kind = SymbolKind::Variable;
158	                        location = self.node_to_location(node);
159	                    }
160	                    "symbol.field" => {
161	                        kind = SymbolKind::Field;
162	                        location = self.node_to_location(node);
163	                    }
164	                    "symbol.parent" => {
165	                        parent = self.node_text(node, source).to_string();
166	                    }
167	                    _ => {}
168	                }
169	            }
170	
171	            if name.is_empty() {
172	                continue;
173	            }
174	
175	            let kind_str = match &kind {
176	                SymbolKind::Function => "function",
177	                SymbolKind::Method => "method",
178	                SymbolKind::Struct => "struct",
179	                SymbolKind::Trait => "trait",
180	                SymbolKind::Enum => "enum",
181	                SymbolKind::TypeAlias => "type_alias",
182	                SymbolKind::Macro => "macro",
183	                SymbolKind::Module => "module",
184	                SymbolKind::Variable => "variable",
185	                SymbolKind::Field => "field",
186	                _ => "unknown",
187	            };
188	
189	            let id = StableSymbolId::new("rust", &file_path_str, kind_str, &name);
190	
191	            // Rust 顶层符号默认是私有的，以大写字母开头的符号大概率是公开 API
192	            let is_exported = name.chars().next().map_or(false, |c| c.is_uppercase())
193	                || matches!(
194	                    kind,
195	                    SymbolKind::Function
196	                        | SymbolKind::Struct
197	                        | SymbolKind::Trait
198	                        | SymbolKind::Enum
199	                );
200	
201	            let parent_id = if parent.is_empty() {
202	                None
203	            } else {
204	                Some(StableSymbolId::new("rust", &file_path_str, "struct", &parent).to_string())
205	            };
206	
207	            let modifiers = if is_exported {
208	                vec!["pub".to_string()]
209	            } else {
210	                vec!["private".to_string()]
211	            };
212	
213	            results.push(Symbol {
214	                id: id.to_string(),
215	                name,
216	                kind,
217	                location,
218	                signature: None,
219	                doc_comment: None,
220	                parent_id,
221	                modifiers,
222	                is_exported,
223	                complexity: None,
224	            });
225	        }
226	
227	        results
228	    }
