291	    fn extract_imports(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<Import> {
292	        let queries = load_rust_queries();
293	        let file_path_str = file_path.to_string_lossy().to_string();
294	        let mut results = Vec::new();
295	
296	        let query = match Query::new(&tree_sitter_rust::language(), &queries.imports) {
297	            Ok(q) => q,
298	            Err(_) => return results,
299	        };
300	
301	        let mut cursor = QueryCursor::new();
302	        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
303	
304	        while let Some(m) = matches.next() {
305	            let mut import_path = String::new();
306	            let mut alias = None;
307	            let mut import_line: u64 = 0;
308	
309	            for capture in m.captures {
310	                let node = capture.node;
311	                let capture_name = query.capture_names()[capture.index as usize];
312	
313	                match capture_name {
314	                    "import.path" => {
315	                        import_path = self.node_text(node, source).to_string();
316	                    }
317	                    "import.name" => {
318	                        alias = Some(self.node_text(node, source).to_string());
319	                    }
320	                    "import" | "import.extern" => {
321	                        import_line = node.start_position().row as u64 + 1;
322	                    }
323	                    _ => {}
324	                }
325	            }
326	
327	            // 对于 extern crate（仅 alias 无 import_path），使用 alias 作为路径
328	            let path = if import_path.is_empty() {
329	                alias.clone().unwrap_or_default()
330	            } else {
331	                import_path
332	            };
333	
334	            if !path.is_empty() {
335	                results.push(Import {
336	                    file_path: file_path_str.clone(),
337	                    import_path: path,
338	                    alias,
339	                    line: import_line,
340	                    resolution: ImportResolution::Unresolved,
341	                });
342	            }
343	        }
344	
345	        results
346	    }
